// Shuffle array utility
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Get 10 random questions from selected chapters
function getQuizQuestions(selectedChapterIds) {
  const pool = QUIZ_QUESTIONS_BANK.filter(q => selectedChapterIds.includes(q.chapter));
  const shuffled = shuffleArray(pool);
  return shuffled.slice(0, 10);
}



