// ── שאלה עם פידבק מיידי ──
function QuizQuestionScreen({questions, onFinish, onHome}) {
  const [cur, setCur]         = useState(0);
  const [answers, setAnswers] = useState({});  // id → picked index
  const q = questions[cur];
  const isLast = cur === questions.length - 1;
  const pickedThisQ = answers[q.id] !== undefined ? answers[q.id] : null;
  const answered = pickedThisQ !== null;

  const pick = (i) => {
    if (answered) return; // לא ניתן לשנות
    setAnswers(prev => ({...prev, [q.id]: i}));
  };

  const goNext = () => {
    if (!answered) return;
    if (isLast) { onFinish(questions, answers); }
    else { setCur(cur + 1); }
  };

  const goPrev = () => {
    if (cur === 0) return;
    setCur(cur - 1);
  };

  // צבע כפתור תשובה
  const optionStyle = (i) => {
    if (!answered) {
      return { background: "white", color: "#3D2912", boxShadow: "0 1px 6px rgba(0,0,0,0.07)" };
    }
    if (i === q.correctAnswer) return { background: "#5F9080", color: "white", boxShadow: "0 3px 10px rgba(95,144,128,0.35)" };
    if (i === pickedThisQ && i !== q.correctAnswer) return { background: "#C0574A", color: "white", boxShadow: "0 3px 10px rgba(192,87,74,0.35)" };
    return { background: "#F0EAE0", color: "#9A8472" };
  };

  const optionIcon = (i) => {
    if (!answered) return <div className="radio-circle" style={{border:"2px solid #C9AD8A"}}>{pickedThisQ===i && <div className="radio-dot" style={{background:"#4A3020"}}/>}</div>;
    if (i === q.correctAnswer) return <span style={{fontSize:18}}>✓</span>;
    if (i === pickedThisQ) return <span style={{fontSize:18}}>✗</span>;
    return null;
  };

  return (
    <Shell>
      <div className="question-header">
        <div className="q-top-row">
          <div className="q-counter">שאלה {cur+1}/{questions.length}</div>
          <div className="q-title">בחינה על הנושאים</div>
          <button onClick={onHome} style={{background:"none",border:"none",color:"rgba(255,255,255,0.7)",fontSize:20,cursor:"pointer",padding:0}}>✕</button>
        </div>
        <div className="progress-track">
          <div className="progress-fill" style={{width:`${((cur+1)/questions.length)*100}%`}}/>
        </div>
      </div>

      <div className="question-body">
        <div className="question-text">{q.question}</div>

        {q.options.map((opt, i) => (
          <button key={i} onClick={() => pick(i)}
            className="option-btn"
            style={{...optionStyle(i), cursor: answered ? "default" : "pointer", transition:"all 0.2s"}}>
            {opt}
            {optionIcon(i)}
          </button>
        ))}

        {/* הסבר לאחר תשובה */}
        {answered && (
          <div style={{
            background: pickedThisQ === q.correctAnswer ? "#EBF3EF" : "#FDECEA",
            borderRadius:12, padding:"12px 14px", marginTop:8,
            borderRight: `3px solid ${pickedThisQ === q.correctAnswer ? "#5F9080" : "#C0574A"}`
          }}>
            <div style={{fontSize:12,fontWeight:700,color: pickedThisQ === q.correctAnswer ? "#5F9080" : "#C0574A",marginBottom:4}}>
              {pickedThisQ === q.correctAnswer ? "✓ נכון!" : "✗ לא נכון"}
            </div>
            <div style={{fontSize:13,color:"#3D2912",lineHeight:1.7,direction:"rtl",textAlign:"right"}}>
              {q.explanation}
            </div>
            <div style={{fontSize:11,color:"#9A8472",marginTop:4}}>📌 {q.source}</div>
          </div>
        )}
      </div>
<div className="question-nav">
  <button className="nav-prev-btn" onClick={goPrev} disabled={cur===0}
    style={{opacity:cur===0?0.4:1,cursor:cur>0?"pointer":"default"}}>
   <IArrR/> לשאלה הקודמת 
  </button>

  <button className="nav-next-btn" onClick={goNext} disabled={!answered}
    style={{background:answered?"#4A3020":"#C8B8A8",cursor:answered?"pointer":"default"}}>
     {isLast ? "לסיום המבחן" : "לשאלה הבאה"} <IArrL/> 
  </button>
</div>
    </Shell>
  );
}

// ── כרטיס שאלה בתוצאות ──
function QuestionCard({q, i, userAnswer, accentColor}) {
  const [open, setOpen] = useState(false);
  const ok = userAnswer === q.correctAnswer;
  const badgeBg = ok ? "#5F9080" : "#C0574A";
  return (
    <div className={`q-card${open?" open":""}`} style={{borderTop:`3px solid ${badgeBg}`}} onClick={()=>setOpen(o=>!o)}>
      <div className="q-card-header">
        <div className="q-card-header-right">
          <span className="q-flip-num" style={{color:accentColor}}>שאלה {i+1}</span>
          <span className="q-flip-badge" style={{background:badgeBg}}>{ok?"✓ נכון":"✗ שגוי"}</span>
        </div>
        <div className="q-flip-question">{q.question}</div>
        <span className="q-card-chevron">{open?<IChevU/>:<IChevD/>}</span>
      </div>
      {open && (
        <div className="q-card-body">
          <div className="q-flip-answer-box">
            <div className="q-answer-row">
              <span className="q-answer-label">התשובה שלך:</span>
              <span className="q-answer-val" style={{color:ok?"#5F9080":"#C0574A",fontWeight:700}}>{q.options[userAnswer]??"-"}</span>
            </div>
            {!ok && (
              <div className="q-answer-row" style={{marginTop:8}}>
                <span className="q-answer-label">התשובה הנכונה:</span>
                <span className="q-answer-val" style={{color:"#5F9080",fontWeight:700}}>{q.options[q.correctAnswer]}</span>
              </div>
            )}
            <div style={{marginTop:10,fontSize:13,color:"#3D2912",lineHeight:1.7,borderTop:"1px solid #E8DDD0",paddingTop:8}}>
              <strong>הסבר: </strong>{q.explanation}
            </div>
            <div style={{fontSize:11,color:"#9A8472",marginTop:4}}>📌 {q.source}</div>
          </div>
        </div>
      )}
    </div>
  );
}

function ResultsScreen({questions, answers, onHome, onRetry}) {
  const correct = questions.filter(q=>answers[q.id]===q.correctAnswer).length;
  const total   = questions.length;
  const pct     = Math.round((correct/total)*100);
  const level =
    pct>=APP_CONFIG.excellentThreshold ? {bg:"#5F9080",title:"כל הכבוד! עבודה מעולה",sub:`ענית נכון על ${correct} מתוך ${total} שאלות.`}
    :pct>=APP_CONFIG.passThreshold     ? {bg:"#C49A3C",title:"אולי כדאי להעמיק בחומר קצת יותר",sub:`ענית נכון על ${correct} מתוך ${total} שאלות.`}
    :                                    {bg:"#C0574A",title:"כדאי לחזור על החומר...",sub:`ענית נכון על ${correct} מתוך ${total} שאלות.`};
  return (
    <Shell>
      <PillHeader title="תוצאות הבחינה" accentColor={level.bg}/>
      <div style={{flex:1,overflowY:"auto",padding:"20px 18px 16px"}}>
        <div className="score-circle-wrap">
          <div className="score-circle" style={{border:`5px solid ${level.bg}`,boxShadow:`0 4px 20px ${level.bg}44`}}>
            <div className="score-pct">{pct}%</div>
            <div className="score-label">ציון סופי</div>
          </div>
        </div>
        <div className="result-message">
          <div className="result-title">{level.title}</div>
          <div className="result-sub">{level.sub}</div>
        </div>
        <div className="review-section-title" style={{color:level.bg}}>לחץ על השאלה לפרטים ולהסבר</div>
        <div className="q-cards-list">
          {questions.map((q,i)=>(
            <QuestionCard key={q.id} q={q} i={i} userAnswer={answers[q.id]} accentColor={level.bg}/>
          ))}
        </div>
        <button className="retry-btn" onClick={onRetry}>נסה שוב</button>
      </div>
      <HomeBar onHome={onHome} bg={level.bg}/>
    </Shell>
  );
}

export default function App() {
  const [screen,     setScreen]     = useState("welcome");
  const [chapter,    setChapter]    = useState(null);
  const [selChapters,setSelChapters]= useState([]);
  const [quizQs,     setQuizQs]     = useState([]);
  const [quizResult, setQuizResult] = useState(null);
  const goHome = () => setScreen("topics");
  // ══════════════════════════════════════════
  // הוספה 2: startQuiz עם אנימציה
  // ══════════════════════════════════════════
  const startQuiz = (ids) => {
    const overlay = document.getElementById('transition-overlay');
    if (!overlay) {
      const qs = getQuizQuestions(ids);
      setSelChapters(ids);
      setQuizQs(qs);
      setScreen("quizInstructions");
      return;
    }
    overlay.classList.add('active');
    spawnCircles();
    setTimeout(() => {
      const qs = getQuizQuestions(ids);
      setSelChapters(ids);
      setQuizQs(qs);
      setScreen("quizInstructions");
      overlay.style.opacity = '0';
      overlay.style.transition = 'opacity 0.4s ease';
    }, 900);
    setTimeout(() => {
      overlay.classList.remove('active');
      overlay.style.opacity = '';
      overlay.style.transition = '';
    }, 1400);
  };

  return (
    <>
      {/* הוספה 3: אלמנט ה-overlay */}
      <div id="transition-overlay" />

      {screen === "welcome"          && <WelcomeScreen onStart={()=>setScreen("topics")}/>}
      {screen === "topics"           && <TopicsScreen onChapter={ch=>{setChapter(ch);setScreen("chapter");}} onQuiz={()=>setScreen("quizSelect")} onHome={goHome}/>}
      {screen === "chapter"&&chapter  && <ChapterScreen chapter={chapter} allChapters={CHAPTERS} onChapter={setChapter} onHome={goHome}/>}
      {screen === "quizSelect"       && <QuizSelectScreen onStart={startQuiz} onHome={goHome}/>}
      {screen === "quizInstructions" && <QuizInstructionsScreen onStart={()=>setScreen("quiz")} onHome={()=>setScreen("quizSelect")}/>}
      {screen === "quiz"             && <QuizQuestionScreen questions={quizQs} onFinish={(qs,ans)=>{setQuizResult({questions:qs,answers:ans});setScreen("results");}} onHome={goHome}/>}
      {screen === "results"&&quizResult && <ResultsScreen questions={quizResult.questions} answers={quizResult.answers} onHome={goHome} onRetry={()=>setScreen("quizSelect")}/>}
    </>
  );

}